# Scratch: ដូចគ្នានឹងប្លុក "បើ នោះ"
akastheat = input("អាកាសធាតុយ៉ាងម៉េច? (ថ្ងៃរាំង/ភ្លៀង): ")
if akastheat == "ថ្ងៃរាំង":
    print("ទៅលេងក្រៅ!")
else:
    print("សរសេរកូដកុំព្យូទ័រ!")

# Scratch: ដូចគ្នានឹងប្លុក "បើ នោះ បើមិនទេ បើ នោះ"
moang = int(input("ឥឡូវម៉ោងប៉ុន្មាន? (0-23): "))
if moang < 10:
    print("អរុណសួស្តី!")
elif moang < 17:
    print("ទិវាសួស្តី!")
else:
    print("សាយ័ណ្ហសួស្តី!")

# Scratch: ដូចគ្នានឹងប្លុក "ធ្វើម្តងទៀត"
for daeng in range(5):
    print(str(daeng + 1) + " ដង: សួស្តី!")
